// Import OpenTelemetry tracing before anything else
import './tracing';

import Fastify from 'fastify';
import helmet from '@fastify/helmet';
import rateLimit from '@fastify/rate-limit';
import cors from '@fastify/cors';
import { offerRoutes } from './routes/offer';
import { tradeRoutes } from './routes/trade';

// Fastify instance must be created before registering plugins
const fastify = Fastify({
  trustProxy: true, // Enable trust proxy for correct client IP detection (rate limiting)
  logger: {
    level: 'info',
    serializers: {
      req (request) {
        return {
          method: request.method,
          url: request.url,
          id: request.id,
          remoteAddress: request.ip,
        };
      }
    }
  }
});

// Health and readiness endpoint for observability
fastify.get('/health', async (req, reply) => {
  return { status: 'ok', uptime: process.uptime() };
});

// Cyber security: Advanced CORS policy
fastify.register(cors, {
  origin: [
    'https://your-production-domain.com',
    'https://admin.your-production-domain.com',
    'http://localhost:3000'
  ],
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: [
    'Content-Type',
    'Authorization',
    'X-Requested-With',
    'Accept',
    'Origin'
  ],
  credentials: true,
  maxAge: 86400,
  strictPreflight: true,
  preflightContinue: false,
  // Defensive: block if method or origin missing in preflight
  hook: 'onRequest',
  preflight: true,
  async preHandler(req, reply) {
    if (req.method === 'OPTIONS') {
      const origin = req.headers['origin'];
      const acrm = req.headers['access-control-request-method'];
      if (!origin || !acrm) {
        reply.code(400).send({ error: 'Missing required CORS preflight headers' });
        return reply;
      }
    }
  }
});



// Cyber security: HTTP headers hardening (strictest settings)
fastify.register(helmet, {
  global: true,
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'"],
      imgSrc: ["'self'", 'data:'],
      objectSrc: ["'none'"],
      frameAncestors: ["'self'"],
      formAction: ["'self'"],
      baseUri: ["'self'"],
      fontSrc: ["'self'", 'https:', 'data:'],
      upgradeInsecureRequests: []
    }
  },
  referrerPolicy: { policy: 'no-referrer' },
  crossOriginResourcePolicy: { policy: 'same-origin' },
  crossOriginOpenerPolicy: { policy: 'same-origin' },
  xssFilter: false, // legacy, not needed
  xDownloadOptions: false, // legacy, not needed
  xPermittedCrossDomainPolicies: { permittedPolicies: 'none' },
  hidePoweredBy: true,
  dnsPrefetchControl: { allow: false },
  frameguard: { action: 'deny' },
  // Add more strict headers as needed
});

// Cyber security: Rate limiting
// Only allow 127.0.0.1 in allowList for local dev, not for tests
const isTest = process.env.NODE_ENV === 'test' || process.env.JEST_WORKER_ID !== undefined;
fastify.register(rateLimit, {
  max: 100,
  timeWindow: '1 minute',
  allowList: isTest ? [] : ['127.0.0.1']
});

// Register modularized routes
offerRoutes(fastify);
tradeRoutes(fastify);


export async function startServer(port = 4000) {
  return fastify.listen({ port });
}

if (require.main === module) {
  // istanbul ignore next: cannot cover CLI entry in tests
  startServer();
}

export default fastify;

