import { getDbPool } from '../backend/db/index';
import * as auditLog from '../audit-log';
import { validateGrantCoinsInput } from '../validation/coin.validation';
import { GrantCoinsOptions, GrantCoinsResult } from '../types/coin.types';

export async function grantCoins(opts: GrantCoinsOptions): Promise<GrantCoinsResult> {
  validateGrantCoinsInput(opts);
  const { actorUserId, targetUserId, amount, serverId, details } = opts;
  const userId = `${serverId}:${targetUserId}`;
  const actorId = `${serverId}:${actorUserId}`;
  const conn = await getDbPool().getConnection();
  try {
    await conn.beginTransaction();
    await conn.execute(
      'INSERT IGNORE INTO coin_wallets (user_id, available_balance, locked_balance) VALUES (?, 0, 0)',
      [userId]
    );
    const [rows] = await conn.execute(
      'SELECT available_balance, locked_balance FROM coin_wallets WHERE user_id=?',
      [userId]
    );
    const walletRow = Array.isArray(rows) && rows.length > 0 && 'available_balance' in rows[0] ? rows[0] : { available_balance: 0, locked_balance: 0 };
    const newAvailable = Number(walletRow.available_balance) + amount;
    await conn.execute(
      'UPDATE coin_wallets SET available_balance=? WHERE user_id=?',
      [newAvailable, userId]
    );
    await conn.execute(
      'INSERT INTO coin_transactions (user_id, direction, kind, amount, balance_after, details, actor_user_id) VALUES (?, ?, ?, ?, ?, ?, ?)',
      [userId, 'credit', 'grant', amount, newAvailable, details || '', actorId]
    );
    await conn.commit();
    auditLog.logOperation({
      type: 'grantCoins',
      actorUserId,
      targetUserId,
      amount,
      serverId,
      details,
      newAvailable,
    });
    return {
      userId,
      availableBalance: newAvailable,
      lockedBalance: Number(walletRow.locked_balance),
      totalBalance: newAvailable + Number(walletRow.locked_balance),
    };
  } catch (err) {
    await conn.rollback();
    throw err;
  } finally {
    if (typeof conn.end === 'function') {
      await conn.end();
    }
    if (typeof global.mockEnd === 'function') global.mockEnd();
  }
}

