// Targeted mutation tests for offer.validation.ts
const { validateOfferInput } = require('../src/validation/offer.validation');

describe('validateOfferInput (mutation targets)', () => {
  it('should throw if opts is missing', () => {
    expect(() => validateOfferInput(undefined)).toThrow();
    expect(() => validateOfferInput(null)).toThrow();
  });

  it('should throw if senderUserId is missing or not a string', () => {
    expect(() => validateOfferInput({ recipientUserId: 'u2', amount: 1 })).toThrow();
    expect(() => validateOfferInput({ senderUserId: 123, recipientUserId: 'u2', amount: 1 })).toThrow();
    expect(() => validateOfferInput({ senderUserId: '', recipientUserId: 'u2', amount: 1 })).toThrow();
    expect(() => validateOfferInput({ senderUserId: '   ', recipientUserId: 'u2', amount: 1 })).toThrow();
  });

  it('should throw if recipientUserId is missing or not a string', () => {
    expect(() => validateOfferInput({ senderUserId: 'u1', amount: 1 })).toThrow();
    expect(() => validateOfferInput({ senderUserId: 'u1', recipientUserId: 123, amount: 1 })).toThrow();
    expect(() => validateOfferInput({ senderUserId: 'u1', recipientUserId: '', amount: 1 })).toThrow();
    expect(() => validateOfferInput({ senderUserId: 'u1', recipientUserId: '   ', amount: 1 })).toThrow();
  });

  it('should throw if senderUserId or recipientUserId contains attack patterns', () => {
    expect(() => validateOfferInput({ senderUserId: '<script>', recipientUserId: 'u2', amount: 1 })).toThrow();
    expect(() => validateOfferInput({ senderUserId: 'u1', recipientUserId: '<img src=x>', amount: 1 })).toThrow();
  });

  it('should not throw for valid input', () => {
    expect(() => validateOfferInput({ senderUserId: 'u1', recipientUserId: 'u2', amount: 1 })).not.toThrow();
  });
});

